def solve(edges: Array[Array[Long]], online: Array[Boolean], k: Long): Long = {
  val n = online.length
  val graph = scala.collection.mutable.HashMap[Long, scala.collection.mutable.ListBuffer[(Long, Long)]]()

  // Build the graph
  for (edge <- edges) {
    val u = edge(0)
    val v = edge(1)
    val cost = edge(2)
    if (online(u)) {
      graph.getOrElseUpdate(u, scala.collection.mutable.ListBuffer.empty).append((v, cost))
    }
  }

  // Dijkstra's algorithm to find the maximum minimum edge cost
  // We use a max-heap to prioritize paths with higher minimum edge cost
  import scala.collection.mutable.PriorityQueue
  val maxHeap = PriorityQueue[(-Long, Long, Long)]()
  maxHeap += (-1, 0, 0)  // (-min_cost, current_node, total_cost)

  val visited = scala.collection.mutable.Set[(Long, Long)]()

  while (maxHeap.nonEmpty) {
    val (minCostNeg, node, totalCost) = maxHeap.dequeue()
    val minCost = -minCostNeg

    if (node == n - 1L) {
      return minCost
    }

    if (visited.contains((node, totalCost))) {
      continue
    }
    visited += (node, totalCost)

    for ((neighbor, edgeCost) <- graph.getOrElse(node, scala.collection.mutable.ListBuffer.empty)) {
      val newTotalCost = totalCost + edgeCost
      if (newTotalCost > k) {
        continue
      }
      val newMinCost = math.min(minCost, edgeCost)
      maxHeap += (-newMinCost, neighbor, newTotalCost)
    }
  }

  -1L
}
